/*
  n8n Node 2: "Build Row"

  Extracts PR data from GitHub webhook, fetches the full diff,
  and composes a rich AI prompt for ALL changes.

  Input:  GitHub Pull Request webhook payload
  Output: Structured data + ai_prompt field for the AI Agent node
*/

const items = $input.all();
const item = items[0];

// ── Normalize payload: n8n GitHub Trigger may nest data under body ──
// The githubTrigger node can put the webhook payload at different levels
const payload = item.json;
const pr = payload.pull_request ?? payload.body?.pull_request ?? null;
const action = payload.action ?? payload.body?.action ?? '';

// Check if this is a test execution (no webhook data)
const isTest = !pr;

if (isTest) {
  // Create sample data for testing
  item.json.ai_prompt = `You are a senior software engineer writing a concise Confluence changelog entry.

Analyze the pull request below and write a 2-3 sentence plain-English summary that:
1. States WHAT was changed (files/modules affected)
2. States WHY or WHAT PURPOSE the change serves
3. Notes any important technical details (schema changes, API changes, breaking changes)

Rules:
- No markdown, no bullet points, no headings — plain text only
- Maximum 60 words
- Be specific about what actually changed

Pull Request: #123 — TEST-456: Sample PR for testing
Author: TestUser
Repository: test-repo
Files Changed: 3 files (+45, -12)
PR Body:
This is a test PR to verify the workflow runs correctly.

Write ONLY the summary paragraph, nothing else.`;

  item.json.jira_id = 'TEST-456';
  item.json.author = 'TestUser';
  item.json.reviewer = 'Morgan Housel';
  item.json.pr_number = '123';
  item.json.pr_title = 'TEST-456: Sample PR for testing';
  item.json.pr_url = 'https://github.com/test/test/pull/123';
  item.json.files_changed = '3 files (+45, -12)';
  item.json.file_count = '3';
  item.json.page_id = '688129';

  return items;
}

// ── Debug: log what we received so you can inspect in n8n execution ──
item.json._debug_action = action;
item.json._debug_pr_merged = pr.merged ?? false;
item.json._debug_pr_state = pr.state ?? 'unknown';

// Only process if PR was actually merged (not just closed)
if (action !== 'closed' || !pr.merged) {
  // Return the item WITH data so downstream nodes still execute
  // and you can see what happened in the execution log
  item.json._skipped = true;
  item.json._skip_reason = `action=${action}, merged=${pr.merged ?? false}`;
  item.json.ai_prompt = '';
  item.json.jira_id = '';
  item.json.author = '';
  item.json.reviewer = '';
  item.json.pr_number = '';
  item.json.pr_title = '';
  item.json.pr_url = '';
  item.json.files_changed = '';
  item.json.file_count = '';
  item.json.page_id = '';
  return items;
}

// Extract PR metadata
const jiraId = pr.title.match(/([A-Z]+-\d+)/)?.[1] ?? 'NO-ID';
const author = pr.user?.login ?? 'Unknown';
const reviewer = pr.merged_by?.login ?? 'Morgan Housel';
const prNumber = pr.number?.toString() ?? '';
const prTitle = pr.title ?? '';
const prUrl = pr.html_url ?? '#';
const repository = payload.repository?.name ?? payload.body?.repository?.name ?? '';
const pageId = '688129';

// Get changed files info
const changedFiles = pr.changed_files ?? 0;
const additions = pr.additions ?? 0;
const deletions = pr.deletions ?? 0;

// Fetch the diff from GitHub
let fullDiff = 'Diff not available';
try {
  const diffUrl = pr.diff_url;
  if (diffUrl) {
    item.json.diff_url = diffUrl;
    fullDiff = '[Diff will be fetched from GitHub]';
  }
} catch (e) {
  fullDiff = 'Could not get diff URL: ' + e.message;
}

// Build files changed summary
const filesChanged = `${changedFiles} files (+${additions}, -${deletions})`;

// Compose the AI prompt
item.json.ai_prompt = `You are a senior software engineer writing a concise Confluence changelog entry.

Analyze the pull request below and write a 2-3 sentence plain-English summary that:
1. States WHAT was changed (files/modules affected)
2. States WHY or WHAT PURPOSE the change serves
3. Notes any important technical details (schema changes, API changes, breaking changes)

Rules:
- No markdown, no bullet points, no headings — plain text only
- Maximum 60 words
- Be specific about what actually changed

Pull Request: #${prNumber} — ${prTitle}
Author: ${author}
Repository: ${repository}
Files Changed: ${filesChanged}
PR Body:
${pr.body ?? 'No description provided'}

Write ONLY the summary paragraph, nothing else.`;

// Pass all fields through for downstream nodes
item.json.jira_id = jiraId;
item.json.author = author;
item.json.reviewer = reviewer;
item.json.pr_number = prNumber;
item.json.pr_title = prTitle;
item.json.pr_url = prUrl;
item.json.files_changed = filesChanged;
item.json.file_count = changedFiles.toString();
item.json.page_id = pageId;
item.json._skipped = false;

return items;

/*
  n8n Node 5: "Append Row"

  Appends a new row to the Confluence table using:
  - Data from "Build Row" node (jira_id, author, pr, files)
  - AI-generated summary from the AI Agent node (via $() reference)
  - Current page body + version from the GET Page node
*/

const items = $input.all();
const item = items[0];

// ── From GET Confluence page (v2 API) ─────────────────────
// v2 API: version.number, body.storage.value
// v1 API: version.number, body.storage.value (same paths)
const currentVersion = item.json.version?.number ?? 1;
const currentBody = item.json.body?.storage?.value ?? '';

// ── From "Build Row" node ─────────────────────────────────
const buildRow = $('Build Row').item.json;
const pageId = buildRow.page_id ?? '688129';
const jiraId = buildRow.jira_id ?? 'NO-ID';
const author = buildRow.author ?? 'Unknown';
const reviewer = buildRow.reviewer ?? 'Morgan Housel';
const prNumber = buildRow.pr_number ?? '';
const prTitle = buildRow.pr_title ?? '';
const prUrl = buildRow.pr_url ?? '#';
const filesChanged = buildRow.files_changed ?? '';
const fileCount = buildRow.file_count ?? '?';

// ── AI Agent output (referenced via $() not item.json) ────
// item.json here is the Confluence GET response, NOT the AI output.
// We must use $('AI Agent') to access the AI node's output.
const aiAgent = $('AI Agent').item.json;
let aiSummary = '';
try {
  aiSummary = (
    aiAgent.output                       // chainLlm / AI Agent node
    ?? aiAgent.text                      // Basic LLM Chain
    ?? aiAgent.response?.text            // alternate chainLlm path
    ?? ''
  ).toString().trim().replace(/\n+/g, ' ');
} catch (e) { aiSummary = ''; }

// Fallback if AI didn't return anything
const summaryCell = aiSummary
  ? aiSummary
  : `Changed ${fileCount} file(s): ${filesChanged.substring(0, 150)}`;

// ── Build new table row ──────────────────────────────────
const prShortTitle = prTitle.substring(0, 60);
const newRow = `<tr>
  <td><p><strong>${jiraId}</strong></p></td>
  <td><p>${author}</p></td>
  <td><p><a href="${prUrl}">PR #${prNumber}: ${prShortTitle}</a></p></td>
  <td><p>${filesChanged}</p></td>
  <td><p>${summaryCell}</p></td>
  <td><p>${reviewer}</p></td>
</tr>`;

// ── Append to existing table or create new one ────────────
let updatedBody;

if (currentBody.includes('<table')) {
  if (currentBody.includes('</tbody>')) {
    updatedBody = currentBody.replace('</tbody>', `${newRow}\n</tbody>`);
  } else {
    updatedBody = currentBody.replace('</table>', `${newRow}\n</table>`);
  }
} else {
  updatedBody = `
<h2>PR Changes Log — AI Summaries</h2>
<p>Auto-maintained by the Agentic Documentation System. Every merged PR adds a row.</p>
<table>
  <tbody>
    <tr>
      <th><p><strong>Story</strong></p></th>
      <th><p><strong>Author</strong></p></th>
      <th><p><strong>Pull Request</strong></p></th>
      <th><p><strong>Files Changed</strong></p></th>
      <th><p><strong>AI Summary of Changes</strong></p></th>
      <th><p><strong>Reviewer</strong></p></th>
    </tr>
    ${newRow}
  </tbody>
</table>
<p><em>Powered by GitHub Actions + n8n + AI Agent</em></p>`;
}

// ── Build the final PUT payload ───────────────────────────
item.json.put_body = {
  id: pageId,
  status: 'current',
  title: 'PR Changes Log - AI Automated',
  body: {
    representation: 'storage',
    value: updatedBody
  },
  version: {
    number: currentVersion + 1,
    message: `PR #${prNumber} merged by ${author}: ${jiraId}`
  }
};

return items;

const items = $input.all();
const item = items[0];
item.json.final_body = JSON.stringify(item.json.put_body);
return items;
